html:
{# ── Payment Voucher Fast — single server call, with attachments ── #}
{% set ctx = frappe.call("avientek.avientek.doctype.payment_request_form.payment_request_form.get_payment_voucher_context", docname=doc.name) %}
{% set cc = ctx.company_currency %}
{% set is_internal_transfer = doc.payment_type == "Internal Transfer" %}
{% set is_tr_lc = doc.is_tr_lc_payment %}

<style>
@page { size: A4 landscape; margin: 8mm 10mm; }
body, .print-format { font-family: 'Segoe UI', Arial, Helvetica, sans-serif; font-size: 9pt; color: #1a1a1a; line-height: 1.25; }
table { border-collapse: collapse; width: 100%; }
.title { text-align: center; font-size: 13pt; font-weight: 700; border: 1.5px solid #000; padding: 6px; margin: 8px 0; letter-spacing: 0.5px; }
.header-blue { background-color: #c9daf8 !important; -webkit-print-color-adjust: exact; print-color-adjust: exact; font-weight: 600; padding: 4px 6px; border: 1px solid #000; font-size: 9pt; }
.header-green { background-color: #d9ead3 !important; -webkit-print-color-adjust: exact; print-color-adjust: exact; font-weight: 600; padding: 4px 6px; border: 1px solid #000; font-size: 9pt; }
.header-red { background-color: #f4cccc !important; -webkit-print-color-adjust: exact; print-color-adjust: exact; font-weight: 600; padding: 4px 6px; border: 1px solid #000; font-size: 9pt; }
.tbl td, .tbl th { border: 1px solid #000; padding: 3px 5px; vertical-align: top; font-size: 9pt; }
.tbl .lbl { width: 35%; background-color: #f5f5f5 !important; -webkit-print-color-adjust: exact; print-color-adjust: exact; font-weight: 500; color: #333; }
.tbl .val { width: 65%; }
.half { width: 50%; vertical-align: top; }
.sig td { border: 1px solid #000; padding: 35px 6px 6px 6px; text-align: center; font-size: 8.5pt; font-weight: 500; }
.sig td small { font-weight: 400; font-size: 7.5pt; color: #555; }
.yellow { background-color: #ffff00 !important; -webkit-print-color-adjust: exact; print-color-adjust: exact; padding: 2px 6px; font-weight: bold; }
.right { text-align: right; }
.center { text-align: center; }
.bold { font-weight: bold; }
.inv td, .inv th { border: 1px solid #000; padding: 3px 4px; font-size: 8.5pt; }
.inv th { background-color: #c9daf8 !important; -webkit-print-color-adjust: exact; print-color-adjust: exact; text-align: center; font-size: 8.5pt; font-weight: 600; }
.total-row { background-color: #e8e8e8 !important; -webkit-print-color-adjust: exact; print-color-adjust: exact; font-weight: bold; }
.att-section { page-break-before: always; margin-top: 15px; }
.att-img { max-width: 100%; border: 1px solid #ccc; margin: 5px 0; }
.page-break { page-break-before: always; }
thead { display: table-header-group; }
tr { page-break-inside: avoid; }
</style>

<div class="print-format">

{% if is_internal_transfer %}
{# ── INTERNAL TRANSFER ── #}
<div class="title">INTERNAL TRANSFER VOUCHER</div>

<table class="tbl"><tr><td class="header-blue center">Company</td><td class="center bold">{{ doc.company }}</td></tr></table>

<table style="margin-top:10px;">
<tr>
<td class="half" style="padding-right:5px;">
<table class="tbl">
<tr><td colspan="2" class="header-blue">FROM (Issued Bank)</td></tr>
<tr><td class="lbl">Bank</td><td class="val">{{ ctx.issued_bank_details.bank or doc.issued_bank or "" }}</td></tr>
<tr><td class="lbl">Account</td><td class="val">{{ doc.account or "" }}</td></tr>
<tr><td class="lbl">Account No.</td><td class="val">{{ doc.account_no or ctx.issued_bank_details.bank_account_no or "" }}</td></tr>
<tr><td class="lbl">Currency</td><td class="val">{{ ctx.issued_bank_currency }}</td></tr>
<tr><td class="lbl">Amount</td><td class="val bold">{{ ctx.issued_amount_fmt }}</td></tr>
</table>
</td>
<td class="half" style="padding-left:5px;">
<table class="tbl">
<tr><td colspan="2" class="header-blue">TO (Receiving Bank)</td></tr>
<tr><td class="lbl">Bank</td><td class="val">{{ ctx.receiving_bank_details.bank or doc.receiving_bank or "" }}</td></tr>
<tr><td class="lbl">Account</td><td class="val">{{ doc.receiving_account or "" }}</td></tr>
<tr><td class="lbl">Account No.</td><td class="val">{{ doc.receving_account_no or ctx.receiving_bank_details.bank_account_no or "" }}</td></tr>
<tr><td class="lbl">Currency</td><td class="val">{{ ctx.receiving_bank_currency }}</td></tr>
<tr><td class="lbl">Amount</td><td class="val bold">{{ ctx.receiving_amount_fmt }}</td></tr>
</table>
</td>
</tr>
</table>

<table class="tbl" style="margin-top:10px;">
<tr><td class="lbl">Voucher No.</td><td class="val">{{ doc.name }}</td></tr>
<tr><td class="lbl">Date</td><td class="val">{{ ctx.posting_date_fmt }}</td></tr>
{% if doc.issued_currency != doc.receiving_currency %}
<tr><td class="lbl">Exchange Rate</td><td class="val">1 {{ doc.issued_currency }} = {{ doc.transfer_exchange_rate or 1 }} {{ doc.receiving_currency }}</td></tr>
{% endif %}
{% if doc.remarks %}
<tr><td class="lbl">Remarks</td><td class="val">{{ doc.remarks }}</td></tr>
{% endif %}
</table>

<table class="sig" style="margin-top:30px;"><tr><td>Prepared By<br/><small>(User Name)</small></td><td>Authorised-By<br/><small>(User &amp; Role)</small></td><td>Approved-By<br/><small>(User &amp; Role)</small></td><td>Approved-By<br/><small>Siby Joy<br/>Corp. Fin Manager</small></td><td>Approved-By<br/><small>Siby Thomas John<br/>Managing Director</small></td></tr></table>

{% else %}
{# ── PAYMENT VOUCHER (shown for both regular and TR/LC) ── #}
<div class="title">PAYMENT VOUCHER</div>

<table class="tbl"><tr><td class="header-blue center">Company</td><td class="center bold">{{ doc.company }}</td></tr></table>

<table style="margin-top:10px;">
<tr>
<td class="half" style="padding-right:5px;">
<table class="tbl">
<tr><td colspan="2" class="header-blue">ISSUED BANK DETAILS</td></tr>
<tr><td class="lbl">Issued Bank</td><td class="val">{{ ctx.issued_bank_details.bank or doc.issued_bank or "" }}</td></tr>
<tr><td class="lbl">Account No.</td><td class="val">{{ ctx.issued_bank_details.bank_account_no or ctx.issued_bank_details.iban or "" }}</td></tr>
<tr><td class="lbl">Currency</td><td class="val">{{ ctx.issued_bank_currency }}</td></tr>
</table>
</td>
<td class="half" style="padding-left:5px;">
<table class="tbl">
<tr><td colspan="2" class="header-blue">VOUCHER DETAILS</td></tr>
<tr><td class="lbl">Voucher No.</td><td class="val">{{ doc.name }}</td></tr>
<tr><td class="lbl">Date</td><td class="val">{{ ctx.posting_date_fmt }}</td></tr>
<tr><td class="lbl">Payment Mode</td><td class="val">{{ doc.payment_mode or "" }}</td></tr>
{% if doc.cheque_date %}<tr><td class="lbl">Cheque Date</td><td class="val">{{ ctx.cheque_date_fmt }}</td></tr>{% endif %}
</table>
</td>
</tr>
</table>

<table style="margin-top:10px;">
<tr>
<td class="half" style="padding-right:5px;">
<table class="tbl">
<tr><td colspan="2" class="header-blue">{{ ctx.party_label|upper }} DETAILS</td></tr>
<tr><td class="lbl">{{ ctx.party_label }} Name</td><td class="val">{{ ctx.party_name }}</td></tr>
<tr><td class="lbl">Address</td><td class="val">{{ ctx.party_address }}</td></tr>
{% if doc.telephone %}<tr><td class="lbl">Telephone</td><td class="val">{{ doc.telephone }}</td></tr>{% endif %}
{% if doc.email %}<tr><td class="lbl">E-Mail</td><td class="val">{{ doc.email }}</td></tr>{% endif %}
</table>
</td>
<td class="half" style="padding-left:5px;">
<table class="tbl">
<tr><td colspan="2" class="header-blue">BANK DETAILS (for TT/TR)</td></tr>
<tr><td class="lbl">Bank Account No.</td><td class="val">{{ ctx.supplier_bank.bank_account_no or ctx.supplier_bank.iban or "" }}</td></tr>
<tr><td class="lbl">Bank Name</td><td class="val">{{ ctx.supplier_bank.bank or "" }}</td></tr>
<tr><td class="lbl">SWIFT Code</td><td class="val">{{ ctx.supplier_swift }}</td></tr>
</table>
</td>
</tr>
</table>

<table class="inv" style="margin-top:10px;">
<tr><th colspan="7" class="header-blue">INVOICE DETAILS</th></tr>
<tr><th style="width:30px;">SI</th><th style="width:120px;">Invoice No.</th><th style="width:72px;">Date</th><th style="width:40px;">Ccy</th><th style="width:90px;">Amount (FC)</th><th style="width:90px;">Amount ({{ cc }})</th><th>Remarks</th></tr>
{% for row in ctx.rows_data %}
<tr>
<td class="center">{{ row.idx }}</td>
<td>{{ row.reference_name }}</td>
<td class="center">{{ row.invoice_date }}</td>
<td class="center">{{ row.currency }}</td>
<td class="right">{{ row.amount_fc }}</td>
<td class="right">{{ row.amount_base }}</td>
<td>{{ row.document_reference }}</td>
</tr>
{% endfor %}
<tr class="total-row">
<td colspan="4" class="center"><strong>TOTAL</strong></td>
<td class="right">{% for t in ctx.formatted_currency_totals %}{{ t }}{% if not loop.last %}<br>{% endif %}{% endfor %}</td>
<td class="right">{{ ctx.total_base_formatted }}</td>
<td></td>
</tr>
</table>

{% if doc.remarks %}
<table class="tbl" style="margin-top:10px;"><tr><td class="header-blue">REMARKS</td></tr><tr><td>{{ doc.remarks }}</td></tr></table>
{% endif %}

<table class="sig" style="margin-top:30px;"><tr><td>Prepared By<br/><small>(User Name)</small></td><td>Authorised-By<br/><small>(User &amp; Role)</small></td><td>Approved-By<br/><small>(User &amp; Role)</small></td><td>Approved-By<br/><small>Siby Joy<br/>Corp. Fin Manager</small></td><td>Approved-By<br/><small>Siby Thomas John<br/>Managing Director</small></td></tr></table>

{% if is_tr_lc %}
{# ── TR/LC APPLICATION (on new page after payment voucher) ── #}
<div class="page-break"></div>

<table style="margin-bottom:4px;"><tr>
<td style="font-weight:bold; font-size:11pt;">{{ doc.company|upper }}</td>
<td style="text-align:right;">Requesting Division: <span class="yellow">{{ doc.department or "" }}</span></td>
</tr></table>

<div class="title">APPLICATION FOR TRUST RECEIPT PAYMENT</div>

<table class="tbl">
<tr><td colspan="2" class="header-blue">BENEFICIARY DETAILS</td></tr>
<tr><td class="lbl">Name of Beneficiary</td><td class="val bold">{{ ctx.party_name }}</td></tr>
<tr><td class="lbl">Address of Beneficiary</td><td class="val">{{ ctx.party_address }}</td></tr>
<tr><td class="lbl">Beneficiary Email</td><td class="val">{{ doc.email or "" }}</td></tr>
<tr><td class="lbl">Beneficiary Bank Name</td><td class="val bold">{{ ctx.supplier_bank.bank or "" }}</td></tr>
<tr><td class="lbl">Beneficiary Account/IBAN</td><td class="val">{{ ctx.supplier_bank.iban or ctx.supplier_bank.bank_account_no or "" }}</td></tr>
<tr><td class="lbl">SWIFT Code</td><td class="val">{{ ctx.supplier_swift }}</td></tr>
</table>

<table class="tbl" style="margin-top:8px;">
<tr><td colspan="2" class="header-blue">TRUST RECEIPT DETAILS</td></tr>
<tr><td class="lbl">TR Amount &amp; Currency</td><td class="val right bold">{{ ctx.tr_currency }} {{ ctx.tr_total_formatted }}</td></tr>
<tr><td class="lbl">Type of TR</td><td class="val bold">{{ doc.tr_type or "" }}</td></tr>
<tr><td class="lbl">Port of Loading</td><td class="val">{{ doc.port_of_loading or "" }}</td></tr>
<tr><td class="lbl">Port of Discharge</td><td class="val">{{ doc.port_of_discharge or "" }}</td></tr>
<tr><td class="lbl">COO of Goods</td><td class="val">{{ doc.coo_of_goods or "" }}</td></tr>
<tr><td class="lbl">Mode of Shipment</td><td class="val">{{ doc.mode_of_shipment or "" }}</td></tr>
<tr><td class="lbl">Description of Goods</td><td class="val">{{ doc.goods_description or "" }}</td></tr>
</table>

{% if doc.tr_type in ["Direct", "Local", "Local TR"] %}
<table class="tbl" style="margin-top:8px;">
<tr><td colspan="2" class="header-green">DOCUMENTS AVAILABLE</td></tr>
<tr><td>Proforma Invoice</td><td class="center" style="width:80px;">{{ "Yes" if doc.has_proforma_invoice else "No" }}</td></tr>
<tr><td>Purchase Order</td><td class="center">{{ "Yes" if doc.has_purchase_order else "No" }}</td></tr>
</table>
{% else %}
<table class="tbl" style="margin-top:8px;">
<tr><td colspan="2" class="header-red">DOCUMENTS REQUIRED (Open TR)</td></tr>
<tr><td>Commercial Invoice</td><td class="center" style="width:80px;">{{ "Yes" if doc.has_commercial_invoice else "No" }}</td></tr>
<tr><td>BL / AWB</td><td class="center">{{ "Yes" if doc.has_bl_awb else "No" }}</td></tr>
<tr><td>Delivery Note</td><td class="center">{{ "Yes" if doc.has_delivery_note else "No" }}</td></tr>
<tr><td>Bill of Entry</td><td class="center">{{ "Yes" if doc.has_bill_of_entry else "No" }}</td></tr>
</table>
{% endif %}

<table class="sig" style="margin-top:30px;"><tr><td>Prepared By<br/><small>(User Name)</small></td><td>Authorised-By<br/><small>(User &amp; Role)</small></td><td>Approved-By<br/><small>(User &amp; Role)</small></td><td>Approved-By<br/><small>Siby Joy<br/>Corp. Fin Manager</small></td><td>Approved-By<br/><small>Siby Thomas John<br/>Managing Director</small></td></tr></table>
{% endif %}

{% endif %}

{# ── ATTACHMENTS (pre-fetched in single batch call) ── #}
{% for att in ctx.row_attachments %}
{% if att.ref_images %}
<div class="att-section">
<div class="header-blue">Attachment: {{ att.ref_label }} - {{ att.ref_name }}</div>
{% for img in att.ref_images %}<img src="{{ img }}" class="att-img" />{% endfor %}
</div>
{% endif %}
{% if att.po_images %}
<div class="att-section">
<div class="header-blue">Purchase Order: {{ att.linked_po }}</div>
{% for img in att.po_images %}<img src="{{ img }}" class="att-img" />{% endfor %}
</div>
{% endif %}
{% if att.costing_images %}
<div class="att-section">
<div class="header-blue">Costing Sheet</div>
{% for img in att.costing_images %}<img src="{{ img }}" class="att-img" />{% endfor %}
</div>
{% endif %}
{% endfor %}

</div>
